class Solution(object):
    def lengthOfLongestSubsequence(self, nums, target):
        # dp[j] = max length of subsequence summing to j (-inf if impossible)
        NEG_INF = float('-inf')
        dp = [NEG_INF] * (target + 1)
        dp[0] = 0
        for num in nums:
            # Traverse backwards (0/1 knapsack)
            for j in range(target, num - 1, -1):
                if dp[j - num] != NEG_INF:
                    dp[j] = max(dp[j], dp[j - num] + 1)
        return dp[target] if dp[target] != NEG_INF else -1
